<?phpdeclare(strict_types=1);namespace api\task;use pocketmine\scheduler\PluginTask;use pocketmine\Server;use pocketmine\math\Vector3;use pocketmine\level\Level;use pocketmine\level\Position;use api\loader;class HotBar extends PluginTask {    public $loader;    public function __construct(Loader $loader) {        $this->loader = $loader;        parent::__construct($loader);    }     public function onRun($currentTick) {        $level = Server::getInstance()->getLevelByName("spawn");        if ($level !== null) {            $players = $level->getPlayers();            if (count($players) > 0) {                $world = Server::getInstance()->getLevelByName("world");                if ($world !== null) {                    $spawnLocation = $world->getSafeSpawn();                    foreach ($players as $player) {                        $position = $player->getPosition();                        $target = new Vector3(28, 28, -12);                        if ($position->distanceSquared($target) <= 28 &&                             $position->getY() >= $target->getY() - 2 &&                             $position->getY() <= $target->getY() + 7) {                            $player->teleport($spawnLocation);                        $worldCount = count($world->getPlayers());                        Loader::getInstance()->grief1->setTitle("§r§f §rОнлайн в мире§7: §a{$worldCount} §r§f");                        Server::getInstance()->getDefaultLevel()->addParticle(Loader::getInstance()->grief1);                        }                    }                }            }        }        foreach ($this->loader->getServer()->getOnlinePlayers() as $p) {            $money = mt_rand(5000, 30000);            $expNeeded = 100 * pow(1.2, Loader::getInstance()->getLvl($p));            if (Loader::getInstance()->getExp($p) >= $expNeeded) {                $newLvl = Loader::getInstance()->getLvl($p) + 1;                $p->sendMessage("\n\n§r §rВы повысили свой уровень с §8[§e" . Loader::getInstance()->getLvl($p) . "§8] §7-> §8[§e" . $newLvl . "§8]");                $p->sendMessage("§r §rЗа повышение уровня, вы получили §a". number_format($money) ."§r§f⩐\n\n");                Loader::getInstance()->remExp($p, $expNeeded);                Loader::getInstance()->addLvl($p, 1);                Loader::getInstance()->addMoney($p, $money);            }            $nexvill = str_repeat(" ", 78);            $pvp = str_repeat(" ", 78);            $r = str_repeat(" ", 75);            $u = str_repeat(PHP_EOL, 8);            $date = time();            $month_en_to_ru = [                'Jan' => 'янв',                'Feb' => 'фев',                'Mar' => 'мар',                'Apr' => 'апр',                'May' => 'май',                'Jun' => 'июн',                'Jul' => 'июл',                'Aug' => 'авг',                'Sep' => 'сен',                'Oct' => 'окт',                'Nov' => 'ноя',                'Dec' => 'дек',            ];            $date_en = date("d M. Y", $date);            $date_ru = str_replace(array_keys($month_en_to_ru), array_values($month_en_to_ru), $date_en);            $ping = "§7{$p->getPing()}";            $o = count($this->loader->getServer()->getOnlinePlayers());            $username = mb_strtolower($p->getName());            $money = number_format(Loader::getInstance()->getMoney($p));            $lvl = Loader::getInstance()->getLvl($p);            $kills = number_format(Loader::getInstance()->getKills($p));            $death = number_format(Loader::getInstance()->getDeath($p));            $player = $p->getPlayer();            $world = Loader::getInstance()->getWorld($p);            $group = Loader::getInstance()->getPrefix($p);            $prefix = Loader::getInstance()->getPrefixTitul($p);            $namerserver = Loader::SERVERNAME_FORMAT;            $clan = Loader::getInstance()->getPrefixClans($p);            $rubmoney = number_format(Loader::getInstance()->getRub($p));            $grouptime = Loader::getInstance()->timeranks->get($username);            $timegroup = Loader::getInstance()->getRemainingTime($p->getName());            $dateserver = date("d.m.y");            $x = floor($p->getX());            $y = floor($p->getY());            $z = floor($p->getZ());            $expNeeded = number_format(100 * pow(1.2, $lvl));            $exp = number_format(Loader::getInstance()->getExp($p));            $timeLeft = Loader::getInstance()->nextUpdate - time();            $minetime = floor($timeLeft / 60);            if (!isset(Loader::getInstance()->nextRarity)) {                Loader::getInstance()->nextRarity = mt_rand(1, 100);            }            $rarityName = Loader::getInstance()->getRarityName(Loader::getInstance()->nextRarity);            if (!isset(Loader::getInstance()->hotbar[$player->getLowerCaseName()])) {                $p->sendTip(                    "{$nexvill}   {$namerserver}§l §7#１§r\n" .                    "{$nexvill}  §7{$date_ru} §7" . $ping . "ms§r\n\n" .                    "{$nexvill} §7  §fРанг§7: {$group}§r §r{$timegroup}§r\n" .                    "{$nexvill} §7  §fПрефикс§7: {$prefix}§r\n" .                    "{$nexvill} §7  §fУР§7: §e{$lvl}§l§e §r| §e§8[§e§d{$exp}§7/§5{$expNeeded}§8]§r\n\n" .                    "{$nexvill} §7  §fМонет§7: §a{$money}§r⩐\n" .                    "{$nexvill} §7  §fРублей§7: §a{$rubmoney}§r§r\n\n" .                    "{$nexvill} §7  §fУбийств§7: §c{$kills}§r\n" .                    "{$nexvill} §7  §fКлан§7: §8[§b{$clan}§r§8]\n\n" .                    "{$nexvill} §r §rОнлайн§7: §e{$o}§7/§6100§r\n\n\n\n\n\n\n\n\n\n\n"                );            }        }    }}